      "  dependsOn:",
      "    - name: platform-base",
      "  healthChecks:",
      "    - apiVersion: apps/v1",
      "      kind: Deployment",
      "      name: repotutor-api",
      "      namespace: repotutor-dev",
      "---",
      "apiVersion: helm.toolkit.fluxcd.io/v2",
      "kind: HelmRelease",
      "metadata:",
      "  name: repotutor-api",
      "  namespace: flux-system",
      "spec:",
      "  interval: 5m",
      "  chart:",
      "    spec:",
      "      chart: ./chart",
      "      sourceRef:",
      "        kind: GitRepository",
      "        name: platform",
      "---",
      "apiVersion: image.toolkit.fluxcd.io/v1",
      "kind: ImageRepository",
      "metadata:",
      "  name: repotutor-api",
      "spec:",
