      platformSignals: Array<{ signal: string; readiness: string }>;
      roomSignals: Array<{ signal: string; readiness: string }>;
      deviceSignals: Array<{ signal: string; readiness: string }>;
      trackSignals: Array<{ signal: string; readiness: string }>;
