      "export function DownshiftCombobox() {",
      "  const combobox = useCombobox({",
      "    items,",
      "    itemToString: (item) => item ?? '',",
      "    inputValue: '',",
      "    selectedItem: items[0],",
      "    highlightedIndex: 0,",
