      "      { id: 'outro', type: 'floating', title: 'Done', description: 'Finish', placement: 'top-end', actions: [{ label: 'Custom', action: ({ next, prev, dismiss, skip, goto }) => { prev(); next(); goto('intro'); skip(); dismiss(); } }] }",
