      "    form: 'roadmap-form',",
      "    invalid: false,",
      "    required: true,",
      "    readOnly: false,",
      "    disabled: false,",
      "    placeholder: { edit: 'Edit title', preview: 'Untitled' },",
      "    translations: { input: 'editable input', edit: 'edit', submit: 'submit', cancel: 'cancel' },",
